import Image from 'next/image';
import AccordionButton from './AccordionButton';

interface AccordionItemsProps<E> {
  title: string;
  hasImage?: true;
  imageUrl?: string;
}

export default function AccordionItems<E>({
  title,
  hasImage,
  imageUrl
}: AccordionItemsProps<E>) {
  return (
    <div className="mb-4 flex flex-col items-center justify-between gap-2 md:flex-row lg:px-10">
      <div className="flex items-center gap-2">
        {hasImage && (
          <Image src={imageUrl!} alt={title} width={30} height={30} />
        )}
        <h3>{title}</h3>
      </div>

      <div className="flex w-full justify-center gap-4 *:cursor-pointer *:rounded *:p-2">
        <AccordionButton variant="edit">Editar</AccordionButton>
        <AccordionButton handleButtonClick={() => {}} variant="delete">Deletar</AccordionButton>
      </div>
    </div>
  );
}
